// // This module shifts the input data to the right on each positive edge of the clock and loads new data from an input when the load signal is low.
module shift_register_4bit
    (
        input clk,
        input load,
        input [3:0] din,
        output reg [3:0] q
    );

    always @(posedge clk)
    begin
        if (load)
            q <= din;
        else
            q <= {q[2:0], 1'b0};
    end

endmodule
